@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_container">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _container;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import",
                "./_content/sv-8e2156baa4694f61b43f8532bfc9a243/Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("initialize", _container, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone during server-side disposal.
            }
        }
        _dotNetRef?.Dispose();
    }
}

let state = null;

export function initialize(container, dotNetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    }

    events.forEach(evt => container.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);

    state = { container, events, resetTimer, timerId };
}

export function dispose() {
    if (state) {
        clearTimeout(state.timerId);
        state.events.forEach(evt =>
            state.container.removeEventListener(evt, state.resetTimer)
        );
        state = null;
    }
}

